Rule.Source:
  import sailpoint.object.QueryOptions;
  import sailpoint.object.Filter;
  import sailpoint.object.Link;
  import sailpoint.object.Identity;
  import sailpoint.api.IdentityService;
  import sailpoint.tools.Util;
  import org.apache.commons.logging.LogFactory;
  import org.apache.commons.logging.Log;

  String userName = null;
  List links = null;
  boolean status = true;
  List applicationList = null;
  String manualTerm = null;
  
  if( null != identity){
	links = identity.getLinks();
    manualTerm = identity.getStringAttribute("manualTerm");
	applicationList = new ArrayList();
	userName = identity.getName();


    if(Util.isNotNullOrEmpty(userName) && ("spadmin".equalsIgnoreCase(userName) || userName.startsWith("sp_"))){
      return false;
    }
	applicationList.add("DB-Peoplesoft-HCM-Primary");
    applicationList.add("Midas Seeker - Provider Onboarding");
    applicationList.add("MDStaff - Ascension");
    applicationList.add("Morrisey");
    applicationList.add("MDStaff - AMITA");

    if(links != null && !Util.nullSafeCaseInsensitiveEq(manualTerm,"Yes")){
      for(Link appLink:links){
        if(  applicationList.contains(appLink.getApplication().getName()) ){
          if(appLink.isDisabled()){
            if(null!=links){
              links = null;
            }
            status = true;
            break;
          } else{
            status = false;
          }
        }

        if(appLink.getApplication().getType().equalsIgnoreCase("Active Directory - Direct")){
          if(!appLink.isDisabled()){
            status = false;
          }                                       
        }
      }
    }

    if(null!=links){
      links = null;
    }

    if (status) {
      String noSync = identity.getAttribute("noSync");
      String noTriggers = identity.getAttribute("noTriggers");

      if (noSync != null && noSync.equalsIgnoreCase("C22")) {
        identity.setAttribute("noSync",null); 
      }
      if (noTriggers != null && noTriggers.equalsIgnoreCase("C22")) {
        identity.setAttribute("noTriggers",null);
      }
      context.saveObject(identity);
      context.commitTransaction();
    }
   
  }

  return status;
